fn resolve_message(
    state: &PushState,
    params: &PushParams,
) -> Result<(String, String), Box<dyn std::error::Error>> {
    let title = params
        .title
        .clone()
        .or_else(|| state.title.clone())
        .ok_or("push: title missing — message stage didn't run")?;
    let body = params
        .body
        .clone()
        .or_else(|| state.body.clone())
        .ok_or("push: body missing — message stage didn't run")?;
    Ok((title, body))
}

